// POST create
// ─────────────────────────────────────────────────────────────────────────────

describe('Upcoming Races API — POST create (authenticated)', () => {
  let createdId

  before(() => {
    cy.setupApiAuthCookies()
  })

  beforeEach(() => {
    cy.setupApiAuthCookies()
  })

  after(() => {
    if (createdId) {
      cy.setupApiAuthCookies()
      cy.request({
        method: 'DELETE',
        url: `${DETAIL_EP}/${createdId}`,
        failOnStatusCode: false,
      })
    }
  })

  it('creates an entry and returns 201 with the new record', () => {
    cy.request({
      method: 'POST',
      url: BASE_EP,
      body: {
        title: 'Cypress Upcoming Test Race',
        // race_date must be today or in the future (schema enforces this)
        race_date: '2099-12-31',
        distance_m: 42195,
      },
      failOnStatusCode: false,
    }).then((res) => {
      expect(res.status).to.eq(201)
      expect(res.body).to.have.property('data')
      const entry = res.body.data
      expect(entry).to.have.property('id')
      expect(entry.title).to.eq('Cypress Upcoming Test Race')
      expect(entry.distance_m).to.eq(42195)
      createdId = entry.id
    })
  })

  it('accepts optional location and notes fields', () => {
    cy.request({
      method: 'POST',
      url: BASE_EP,
      body: {
        title: 'Cypress Optional Fields Race',
        race_date: '2099-11-01',
        distance_m: 10000,
        location: 'Bali, Indonesia',
        notes: 'Target sub-50',
      },
      failOnStatusCode: false,
    }).then((res) => {
      if (res.status === 201) {
        const entry = res.body.data
        expect(entry.location).to.eq('Bali, Indonesia')
        expect(entry.notes).to.eq('Target sub-50')
        // cleanup
        cy.request({
          method: 'DELETE',
          url: `${DETAIL_EP}/${entry.id}`,
          failOnStatusCode: false,
        })
      }
    })
  })

  it('returns 400 when title is missing', () => {
    cy.request({
      method: 'POST',
      url: BASE_EP,
      body: {
        race_date: '2099-12-31',
        distance_m: 10000,
      },
      failOnStatusCode: false,
    }).then((res) => {
      expect(res.status).to.eq(400)
    })
  })

  it('returns 400 when race_date is missing', () => {
    cy.request({
      method: 'POST',
      url: BASE_EP,
      body: {
        title: 'No Date Race',
        distance_m: 10000,
      },
      failOnStatusCode: false,
    }).then((res) => {
      expect(res.status).to.eq(400)
    })
  })

  it('returns 400 when distance_m is missing', () => {
    cy.request({
      method: 'POST',
      url: BASE_EP,
      body: {
        title: 'No Distance Race',
        race_date: '2099-12-31',
      },
      failOnStatusCode: false,
    }).then((res) => {
      expect(res.status).to.eq(400)
    })
  })

  it('returns 400 when race_date is in the past', () => {
    cy.request({
      method: 'POST',
      url: BASE_EP,
      body: {
        title: 'Past Race',
        race_date: '2020-01-01',
        distance_m: 10000,
      },
      failOnStatusCode: false,
    }).then((res) => {
      expect(res.status).to.eq(400)
    })
  })

  it('returns 400 when distance_m is zero or negative', () => {
    cy.request({
      method: 'POST',
      url: BASE_EP,
      body: {
        title: 'Zero Distance Race',
        race_date: '2099-12-31',
        distance_m: 0,
      },
      failOnStatusCode: false,
    }).then((res) => {
      expect(res.status).to.eq(400)
    })
  })
})

